const data = $input.first().json;
const platform = data.platform || 'instagram';
const images = data.images || [];
const captions = data.captions || [];
const metadata = data.metadata || {};

// Validate required fields
if (!images.length && !data.image_url) {
  throw new Error('No images provided');
}

return [{
  json: {
    platform,
    caption: captions[0] || data.caption || '',
    image_url: data.image_url || '',
    image_b64: images[0]?.b64 || '',
    topic: metadata.topic || data.topic || '',
    timestamp: new Date().toISOString(),
    source: metadata.source || 'aura-bot',
  }
}];

// Instagram Graph API posting
// Requires: INSTAGRAM_ACCESS_TOKEN, INSTAGRAM_ACCOUNT_ID in N8N env vars
const item = $input.first().json;
const token = $env.INSTAGRAM_ACCESS_TOKEN || '';
const accountId = $env.INSTAGRAM_ACCOUNT_ID || '';

if (!token || !accountId) {
  // Mock response when credentials not configured
  return [{
    json: {
      success: false,
      mock: true,
      message: 'Configure INSTAGRAM_ACCESS_TOKEN and INSTAGRAM_ACCOUNT_ID in N8N env vars',
      post_data: item,
      post_url: '',
    }
  }];
}

// Step 1: Create media container
const createUrl = `https://graph.facebook.com/v18.0/${accountId}/media`;
const createBody = {
  caption: item.caption,
  access_token: token,
};

if (item.image_url) {
  createBody.image_url = item.image_url;
} else if (item.image_b64) {
  // Would need to upload to a CDN first - simplified for now
  return [{ json: { success: false, error: 'B64 upload not implemented in this flow - use image_url' } }];
}

// This will be executed by N8N's HTTP node in production
// For now return the constructed payload
return [{
  json: {
    success: true,
    mock: !token,
    endpoint: createUrl,
    payload: createBody,
    caption: item.caption,
    topic: item.topic,
  }
}];

const result = $input.first().json;
return [{
  json: {
    ok: result.success !== false,
    post_url: result.post_url || '',
    mock: result.mock || false,
    message: result.message || (result.success ? 'Posted successfully' : result.error || 'Unknown error'),
    timestamp: new Date().toISOString(),
  }
}];
